def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a in range(1, 15):
                factor = np.sin(ratio * a * np.pi) + np.cos(ratio * a * np.e)
                temp = (factor ** 2 + 1) * (a ** 3) / (a + 0.7)
                if a % 4 == 0:
                    temp *= 0.85
                elif a % 5 == 0:
                    temp *= 1.1
                score += temp
            mod_check = int(capacity + item)
            if mod_check % 7 == 0 or mod_check % 11 == 0:
                score *= 0.79
            if score > 20:
                score /= (np.log1p(score) + 1)
        elif 0.05 <= ratio < 0.2:
            product = 1.0
            for n in range(1, int(capacity) + 5):
                term = (ratio + np.sin(n * ratio)) / (1 + n / 10)
                product *= max(term, 0.01)
                if product > 5e7:
                    product = np.power(product, 0.25)
                    break
            val_mod = int(product * 1000) % 400
            score = np.tanh(ratio * val_mod / (val_mod + 1)) * 10
            if (int(capacity) % 8 == 0) and ((item * 5) % 4 == 0):
                score += 6.2
            else:
                score -= 1.3
            extra_sum = 0
            for x in range(1, 8):
                fract_part = ((ratio ** 1.3) * x ** 3) % 1
                extra_sum += fract_part * (x * 2.1)
            score += extra_sum / 7
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 9):
                increment = (ratio ** (m + 1.5)) * (m ** 3.1) / ((m + 1.7) ** 1.1)
                if m % 2 == 0:
                    increment *= 0.95
                else:
                    increment *= 1.05
                score += increment
            remainder = capacity - item
            if remainder < 4:
                score += 12 + remainder * 0.75
            else:
                score -= remainder * 1.1
            if score < -7:
                score = abs(score) * 0.25 + 3
            if int(capacity) % 9 == 0:
                score *= 1.35
            if score > 25:
                score /= 3.5
        elif 0.5 < ratio <= 0.8:
            penalty_base = 0
            for p in range(1, 12):
                power_val = ((ratio - 0.5) ** p) * (p ** 2.1)
                if p % 3 == 0:
                    power_val *= 1.1
                penalty_base += power_val
                if penalty_base > 80:
                    penalty_base = np.log1p(penalty_base) * 1.5
                    break
            score = penalty_base * 15
            if capacity < item * 1.1:
                score += 22
            if (int(capacity * 4) % 9 == 0) and (int(item * 7) % 8 == 0):
                score -= 8
            if score < 0:
                score *= -1.25
                score += 7
            if score > 130:
                score = 130
        elif 0.8 < ratio <= 1.2:
            penalty_ext = 0
            diff = ratio - 0.8
            for q in range(1, 14):
                penalty_ext += ((diff) ** q) * (q ** 3) / (q + 0.75)
                if q % 4 == 0:
                    penalty_ext *= 0.85
            score = penalty_ext * 25
            if capacity < item * 1.4:
                score += 30
            if (int(capacity * 4) % 6 == 0) and (int(item * 11) % 7 == 0):
                score -= 10
            for z in range(1, 8):
                score += ((diff / (z + 0.33)) % 1) * (z * 2.3)
            if score < 0:
                score = abs(score) * 0.6
            if score > 1800:
                score = 1800
        else:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 16):
                term = ((diff) ** r) * (r ** 3.8)
                if term > 20000:
                    term = np.sqrt(term) * 1.1
                super_penalty += term
            score = super_penalty * 35
            if capacity < item * 2.5:
                score += 45
            if (int(capacity * 17) % 5 == 0) and (int(item * 19) % 6 == 0):
                score -= 14
            for w in range(3, 9):
                score += ((diff / w) % 1) * (w * 2.8)
            if score < 0:
                score = abs(score) * 0.75 + 6
            if score > 2500:
                score = 2500
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.5)
        elif capacity < 7:
            score *= 2.8
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = np.max(finite_priorities) * (20 + top_count) - median_val * 0.85
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) * 1.1 if finite_priorities.size > 0 else 0
    return priorities
